insert into message_templates (id, name, category, content, allowed_variables, is_default, active, version) values
  ('06e0b2d6-1e44-531d-892e-ccb2661b2444', 'Primeira abordagem — genérica', 'first_contact', 'Olá, tudo bem? Encontrei a {{company_name}} enquanto pesquisava empresas de {{category}} em {{city}}. Trabalho com criação de sites institucionais para negócios locais e identifiquei alguns pontos que podem ajudar a apresentar melhor a empresa. Se fizer sentido, posso te mostrar uma sugestão objetiva, sem compromisso.', ARRAY['company_name','category','city']::text[], true, true, 1),
  ('8dca70b8-c40c-535c-8bf2-154acfa6bce2', 'Primeira abordagem — clínica', 'first_contact', 'Olá! Vi a {{company_name}} em {{city}} e trabalho com sites para clínicas que querem facilitar o agendamento e passar mais confiança. Posso te enviar uma ideia rápida?', ARRAY['company_name','city']::text[], false, true, 1),
  ('dee38199-cecb-5189-8edd-669cdb76eb09', 'Follow-up — retomada', 'follow_up', 'Oi! Passando para saber se você chegou a ver a sugestão que enviei para a {{company_name}}. Fico à disposição.', ARRAY['company_name']::text[], true, true, 1),
  ('9f4b9bac-a888-5db7-81f8-f5c6b0adacd7', 'Última tentativa', 'last_attempt', 'Olá! Vou encerrar meu contato por aqui para não incomodar. Se quiser retomar sobre o site da {{company_name}}, é só me chamar. Abraço!', ARRAY['company_name']::text[], false, true, 1);
